252→  spices: string[] = [],
253→  styleWishes: string[] = [],
254→  errorTranslations?: ErrorTranslations
255→): Promise<MealPlan> => {
256→  const errors = errorTranslations ?? translations.English.errors;
257→
258→  if (!apiKey) throw new Error(errors.apiKeyRequired);
259→
260→  const prompt = buildRecipePrompt({
261→    ingredients,
262→    people,
263→    meals,
264→    diet,
265→    language,
266→    spices,
267→    styleWishes,
268→  });
269→
270→  try {
271→    const controller = new AbortController();
272→    const timeoutId = setTimeout(() => controller.abort(), API_CONFIG.TIMEOUT_MS);
273→
274→    const response = await fetch(
275→      `${API_CONFIG.BASE_URL}/${API_CONFIG.MODEL}:generateContent?key=${apiKey}`,
276→      {
277→        method: "POST",
278→        headers: {
279→          "Content-Type": "application/json",
280→        },
281→        body: JSON.stringify({
282→          contents: [
283→            {
284→              parts: [{ text: prompt }],
285→            },
286→          ],
287→        }),
288→        signal: controller.signal,
289→      }
290→    );
291→
292→    clearTimeout(timeoutId);
293→
294→    if (!response.ok) {
295→      const errorData = await response.json();
296→      throw new Error(errorData.error?.message || errors.fetchFailed);
297→    }
298→
299→    const data = await response.json();
300→    const text = data.candidates?.[0]?.content?.parts?.[0]?.text;
301→
302→    if (!text) throw new Error(errors.emptyResponse);
303→
304→    return parseRecipeResponse(text, errors);
305→  } catch (error) {
306→    console.error("LLM Error:", error);
307→
308→    // Handle specific error types with user-friendly messages
309→    if (error instanceof Error) {
310→      if (error.name === 'AbortError') {
311→        throw new Error(errors.timeout);
312→      }
313→      if (error.message.includes('Failed to fetch')) {
314→        throw new Error(errors.networkError);
315→      }
316→      // Re-throw with original message if already a user-friendly error
317→      throw error;
318→    }
319→
320→    throw new Error(errors.unexpectedError);
321→  }
