  1→import { z } from 'zod';
  2→import { API_CONFIG } from '../constants';
  3→import { translations } from '../constants/translations';
  4→import type { PantryItem, MealPlan } from '../types';
  5→
  6→/**
  7→ * Sanitizes user input to prevent prompt injection attacks.
  8→ *
  9→ * @param input - The user-provided string to sanitize
 10→ * @param maxLength - Maximum allowed length (default: 200 for short fields, 1000 for long fields)
 11→ * @returns Sanitized string safe for inclusion in LLM prompts
 12→ */
 13→const sanitizeUserInput = (input: string, maxLength: number = 200): string => {
 14→  if (!input) return '';
 15→
 16→  // Limit length to prevent excessively long inputs
 17→  let sanitized = input.slice(0, maxLength);
 18→
 19→  // Replace newlines with spaces to prevent multi-line prompt injection
 20→  sanitized = sanitized.replace(/[\r\n]+/g, ' ');
 21→
 22→  // Remove control characters that could break prompt structure
 23→  // eslint-disable-next-line no-control-regex
 24→  sanitized = sanitized.replace(/[\x00-\x1F\x7F]/g, '');
 25→
 26→  // Trim excessive whitespace
 27→  sanitized = sanitized.replace(/\s+/g, ' ').trim();
 28→
 29→  return sanitized;
 30→};
 31→
 32→/**
 33→ * Zod schemas for runtime validation of LLM responses.
 34→ * These ensure the parsed JSON matches our expected types.
 35→ * Exported for reuse in URL parameter validation.
 36→ */
 37→export const IngredientSchema = z.object({
 38→  item: z.string(),
 39→  amount: z.string(),
 40→  unit: z.string().optional(),
 41→});
 42→
 43→export const NutritionSchema = z.object({
 44→  calories: z.number(),
 45→  carbs: z.number(),
 46→  fat: z.number(),
 47→  protein: z.number(),
 48→});
 49→
 50→export const RecipeSchema = z.object({
 51→  id: z.string(),
 52→  title: z.string(),
 53→  time: z.string(),
 54→  ingredients: z.array(IngredientSchema),
 55→  instructions: z.array(z.string()),
 56→  usedIngredients: z.array(z.string()),
 57→  // Optional because shared recipes exclude missingIngredients (not relevant in standalone view)
 58→  missingIngredients: z.array(IngredientSchema).optional(),
 59→  nutrition: NutritionSchema.optional(),
 60→  comments: z.string().optional(),
 61→});
 62→
 63→export const MealPlanSchema = z.object({
 64→  recipes: z.array(RecipeSchema),
 65→  shoppingList: z.array(IngredientSchema),
 66→});
 67→
 68→/**
 69→ * Parameters for building a recipe prompt.
 70→ */
 71→/**
 72→ * Error translations for user-facing error messages.
 73→ */
 74→export interface ErrorTranslations {
 75→  invalidStructure: string;
 76→  tryAgain: string;
 77→  invalidJson: string;
 78→  apiKeyRequired: string;
 79→  fetchFailed: string;
 80→  emptyResponse: string;
 81→  timeout: string;
 82→  networkError: string;
 83→  unexpectedError: string;
 84→}
 85→
 86→
 87→/**
 88→ * Parameters for building a recipe prompt.
 89→ */
 90→export interface RecipePromptParams {
 91→  ingredients: PantryItem[];
 92→  people: number;
 93→  meals: number;
 94→  diet: string;
 95→  language: string;
 96→  spices?: string[];
 97→  styleWishes?: string[];
 98→}
 99→
100→/**
101→ * Builds the prompt for recipe generation.
102→ * Exported so it can be used by the copy-paste flow.
103→ */
104→export const buildRecipePrompt = ({
105→  ingredients,
106→  people,
107→  meals,
108→  diet,
109→  language,
110→  spices = [],
111→  styleWishes = [],
112→}: RecipePromptParams): string => {
113→  const pantryList = ingredients
114→    .map((v) => `- ${sanitizeUserInput(v.name)} (${sanitizeUserInput(v.amount)}) [ID: ${v.id}]`)
115→    .join("\n");
116→
117→  const spiceList = spices.length > 0
118→    ? `Available Spices/Staples (Do NOT add to shopping list): ${spices.map(s => sanitizeUserInput(s)).join(", ")}`
119→    : "No extra spices or staples available.";
120→
121→  const sanitizedStyleWishes = styleWishes
122→    .map(wish => sanitizeUserInput(wish, 200))
123→    .filter(wish => wish.length > 0)
124→    .join(", ");
125→  const styleWishesText = sanitizedStyleWishes
126→    ? `STYLE/WISHES: ${sanitizedStyleWishes}`
127→    : "";
128→
129→  const sanitizedDiet = sanitizeUserInput(diet, 200);
130→
131→  return `
132→    You are a smart recipe planner. 
133→
134→    I need a meal plan for ${meals} distinct meals for ${people} people.
135→
136→    ${ingredients.length > 0 ? `I have these ingredients in my pantry:\n${pantryList}` : `My pantry is empty. Choose suitable ingredients for the recipes.`}
137→
138→    ${spiceList}
139→
140→    DIETARY PREFERENCE: ${sanitizedDiet}
141→    LANGUAGE: ${language}
142→    ${styleWishesText}
143→
144→    RULES:
145→    1. STRICTLY follow the dietary preference: ${sanitizedDiet}.${sanitizedStyleWishes ? ` Also respect the style/wishes: ${sanitizedStyleWishes}. This should guide the cuisine type, dietary restrictions, or cooking style preferences.` : ''}
146→    2. ${ingredients.length > 0 ? 'Prioritize using as many of my pantry ingredients as possible.' : 'Choose suitable ingredients for delicious, balanced meals.'}
147→    3. The portion sizes must be realistic for ${people} people.
148→    4. ${ingredients.length > 0 ? `When a pantry item's quantity is enough for one recipe (e.g., 500 g potatoes as a side for 2 people, or 400 g chicken breast as a main for 2 people), use it entirely in that recipe rather than splitting it across multiple recipes. Only distribute a pantry item across recipes if the total quantity is large enough that each recipe receives a full, realistic serving per person.` : 'Ensure each recipe uses realistic quantities of each ingredient.'}
149→    5. Ensure variety: The ${meals} meals should be distinct in style and flavor profile.
150→    6. For every meal, use the five basic flavors - sweetness, sourness, bitterness, saltiness, and umami - and the five basic textures - soft, crispy, chewy, crunchy, and tender - as a guidance. Try to balance them, but never dogmatically.
151→    7. For every meal, check if a sauce, gravy or dip could enhance the meal.
152→    8. ${ingredients.length > 0 ? `If there are too few ingredients to generate ${meals} meals for ${people} people, do not stretch the same few ingredients across all meals if it results in repetitive or poor-quality recipes. Instead generate recipes with different ingredients that will have to be bought.` : `For every meal, choose ingredients that work well together and create balanced, delicious meals.`}
153→    9. ${ingredients.length > 0 ? `If I have too few ingredients for the requested amount of meals, supplement with additional ingredients from your own knowledge and add them to the "missingIngredients" array.` : `All ingredients ${spices.length > 0 ? '(except available spices/staples)' : ''} will need to be purchased and should be listed in the "missingIngredients" array. Set "usedIngredients" to an empty array.`}
154→    10. Let the available spices and staples guide the recipes. Not all spices or staples need to be used.
155→    11. Output ALL text (recipe titles, ingredients, instructions, shopping list items) in ${language}.
156→    12. The "ingredients" array must contain EVERY single ingredient needed for the recipe: pantry items, items to buy, and any spice rack items used in the recipe.
157→    13. The "missingIngredients" array must ONLY contain items I need to buy. DO NOT include spices and staples if they are listed in "Available Spices/Staples".
158→    14. Each recipe's "missingIngredients" must list only the ingredients that specific recipe requires to be purchased, at the amount needed for that recipe alone. Do not combine amounts across recipes in "missingIngredients".
159→    15. The "item" field MUST NOT include the "amount". Keep them separate. Example: {"item": "Carrots", "amount": "500g"}, NOT {"item": "Carrots 500g"}.
160→    16. Ensure "missingIngredients" is a list of distinct objects, not one combined string.
161→    17. If you need to buy spices or staples, use the "missingIngredients" array.
162→    18. The top-level "shoppingList" is the aggregated shopping list across all recipes. If the same ingredient is needed in multiple recipes, combine the totals here.
163→    19. Return ONLY valid JSON. No JSON-comments, no markdown formatting, no code blocks, no enumeration, no entrance statements before the JSON ...
